'use client';

import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import { useEffect, useState } from 'react';
import { ShieldAlert, LogOut, Clock, Ban } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { signOut } from 'next-auth/react';

export default function BannedPage() {
  const { data: _, status } = useSession();
  const _router = useRouter();
  const [userData, setUserData] = useState<Record<string, unknown> | null>(null);

  useEffect(() => {
    if (status === 'unauthenticated') {
      router.push('/auth/signin');
      return;
    }

    const checkStatus = async () => {
      if (status !== 'authenticated') return;
      try {
        const res = await fetch('/api/user/me');
        if (res.ok) {
          const { user } = await res.json();
          const isRestricted =
            user.isBanned || (user.bannedUntil && new Date(user.bannedUntil) > new Date());

          if (!isRestricted) {
            router.push('/dashboard');
          } else {
            setUserData(user);
          }
        }
      } catch (err) {
        // eslint-disable-next-line no-console
        console.error('Failed to check restriction status:', err);
      }
    };

    // Initial check
    checkStatus();

    // Poll every 5 seconds
    const interval = setInterval(checkStatus, 5000);
    return () => clearInterval(interval);
  }, [status, router]);

  if (status === 'loading' || !userData) {
    return (
      <div className="min-h-screen bg-[#0a0a0a] flex items-center justify-center text-white font-mono">
        Verifying account status...
      </div>
    );
  }

  const isTimeout = userData.bannedUntil && new Date(userData.bannedUntil) > new Date();

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white flex flex-col items-center justify-center p-6 selection:bg-red-500/30">
      <div className="max-w-md w-full space-y-8 text-center">
        <div className="flex justify-center">
          <div className="p-4 bg-red-500/10 rounded-full border border-red-500/20 animate-pulse">
            <ShieldAlert className="w-16 h-16 text-red-500" />
          </div>
        </div>

        <div className="space-y-2">
          <h1 className="text-4xl font-black tracking-tighter uppercase italic">
            Access Restricted
          </h1>
          <p className="text-gray-400 text-sm font-medium">
            Your account has been suspended by the platform administration.
          </p>
        </div>

        <div className="bg-[#111] border border-white/5 rounded-3xl p-8 space-y-6 text-left">
          <div className="space-y-4">
            <div className="flex items-start gap-4">
              <Ban className="w-5 h-5 text-red-500 mt-1 shrink-0" />
              <div>
                <p className="text-xs font-black uppercase tracking-widest text-gray-500 mb-1">
                  Reason
                </p>
                <p className="text-white font-bold leading-relaxed">
                  {userData.banReason ||
                    'Terms of Service violation or community guidelines breach.'}
                </p>
              </div>
            </div>

            {isTimeout && (
              <div className="flex items-start gap-4">
                <Clock className="w-5 h-5 text-amber-500 mt-1 shrink-0" />
                <div>
                  <p className="text-xs font-black uppercase tracking-widest text-gray-500 mb-1">
                    Duration
                  </p>
                  <p className="text-white font-bold">
                    Restricted until {new Date(userData.bannedUntil).toLocaleString()}
                  </p>
                </div>
              </div>
            )}
          </div>

          <div className="pt-4 space-y-3">
            <p className="text-[10px] text-gray-600 leading-relaxed text-center">
              {isTimeout
                ? 'You will be able to log back in once the restriction period ends.'
                : 'This suspension is permanent. If you believe this is a mistake, please reach out through official support channels.'}
            </p>
          </div>
        </div>

        <Button
          onClick={() => signOut({ callbackUrl: '/auth/signin' })}
          variant="outline"
          className="w-full rounded-2xl border-white/10 hover:bg-white/5 py-6 text-lg font-bold group"
        >
          <LogOut className="w-5 h-5 mr-2 transition-transform group-hover:-translate-x-1" />
          Sign Out
        </Button>
      </div>
    </div>
  );
}

'use client';

import { useSession } from 'next-auth/react';
import { useRouter, useSearchParams } from 'next/navigation';
import { useState, useEffect, Suspense } from 'react';

function SetupContent() {
  const { data: session, update } = useSession();
  const _router = useRouter();
  const searchParams = useSearchParams();
  const callbackUrl = searchParams?.get('callbackUrl') || '/dashboard';

  const [username, setUsername] = useState('');
  const [displayName, setDisplayName] = useState('');
  const [isAvailable, setIsAvailable] = useState<boolean | null>(null);
  const [reason, setReason] = useState('');
  const [isChecking, setIsChecking] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const safeJson = async (res: Response) => {
    const contentType = res.headers.get('content-type');
    if (contentType && contentType.includes('application/json')) {
      return await res.json();
    }
    throw new Error(
      `Unexpected response format: ${contentType || 'unknown'}. The request may have been redirected.`,
    );
  };

  // Debounced username check
  useEffect(() => {
    if (!username) {
      setIsAvailable(null);
      setReason('');
      return;
    }

    const validPrefix = /^[a-z0-9_]*$/.test(username);
    if (!validPrefix) {
      setIsAvailable(false);
      setReason('Only lowercase letters, numbers, and underscores allowed');
      return;
    }

    setIsChecking(true);
    const timer = setTimeout(async () => {
      try {
        // eslint-disable-next-line no-console
        console.log(`🔍 Checking username: ${username}`);
        const res = await fetch(`/api/user/check-username?username=${username}`);
        const data = await safeJson(res);
        // eslint-disable-next-line no-console
        console.log(`✅ Username check result:`, data);
        setIsAvailable(data.available);
        setReason(data.reason || '');
      } catch (err) {
        // eslint-disable-next-line no-console
        console.error('❌ Failed to check username:', err);
        setReason('Failed to verify username availability');
      } finally {
        setIsChecking(false);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [username]);

  // Pre-fill display name and redirect if already set up
  useEffect(() => {
    if (session?.user?.username) {
      _router.push(callbackUrl);
    }
  }, [session, callbackUrl]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    // eslint-disable-next-line no-console
    console.log('🔘 [Setup] Form submitted with:', { username, displayName, isAvailable });

    if (isAvailable !== true) {
      // eslint-disable-next-line no-console
      console.warn('⚠️ Cannot submit: username is not available or still checking.');
      return;
    }

    setIsSubmitting(true);
    setReason('');
    try {
      console.log('📡 [Setup] Sending setup request to /api/user/setup...');
      const res = await fetch('/api/user/setup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, displayName }),
      });

      console.log(`📦 [Setup] Received response (Status ${res.status})`);

      if (res.ok) {
        const data = await safeJson(res);
        console.log('✨ [Setup] Success! Updating session and redirecting...');

        // Pass role too so JWT callback can capture it if returned
        await update({ username, displayName, platformRole: data.role });

        // Use a hard refresh to ensure the session cookie is correctly
        // picked up by the middleware on the next request.
        window.location.href = callbackUrl;
      } else {
        try {
          const data = await safeJson(res);
          console.error('❌ [Setup] Server error data:', data);
          setIsAvailable(false);
          setReason(data.message || 'Failed to set up profile');
        } catch (parseErr) {
          console.error('❌ [Setup] Parse error during failure handling:', parseErr);
          setReason(`Server error (Status ${res.status}). Please refresh and try again.`);
        }
      }
    } catch (err) {
      console.error('❌ [Setup] Critical network error:', err);
      setReason(
        err instanceof Error
          ? err.message
          : 'An unexpected error occurred. Please check your connection.',
      );
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#111111] px-4 py-8 text-white">
      <div className="w-full max-w-sm sm:max-w-md bg-[#1a1a1a] rounded-2xl sm:rounded-3xl p-6 sm:p-8 border border-[#333] shadow">
        <div className="sm:mx-auto sm:w-full sm:max-w-md mb-8">
          <h2 className="text-center text-3xl font-extrabold text-[#4a90e2]">Complete setup</h2>
          <p className="mt-2 text-center text-sm text-gray-400">
            Choose a username to start using EchoDeck
          </p>
        </div>

        <div className="sm:mx-auto sm:w-full sm:max-w-md">
          <form className="space-y-6" onSubmit={handleSubmit}>
            <div>
              <label htmlFor="username" className="block text-sm font-medium text-gray-300">
                Username
              </label>
              <div className="mt-1 relative rounded-md shadow-sm">
                <input
                  id="username"
                  name="username"
                  type="text"
                  required
                  value={username}
                  onChange={(e) => setUsername(e.target.value.toLowerCase())}
                  className="appearance-none block w-full px-3 py-2 border border-[#333] rounded-md shadow-sm placeholder-gray-500 bg-[#222] text-white focus:outline-none focus:ring-[#4a90e2] focus:border-[#4a90e2] sm:text-sm"
                  placeholder="your_username"
                />
                {username.length > 0 && (
                  <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
                    {isChecking ? (
                      <span className="text-gray-500 text-xs">Checking...</span>
                    ) : isAvailable === true ? (
                      <svg
                        className="h-5 w-5 text-green-500"
                        fill="currentColor"
                        viewBox="0 0 20 20"
                      >
                        <path
                          fillRule="evenodd"
                          d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"
                          clipRule="evenodd"
                        />
                      </svg>
                    ) : isAvailable === false ? (
                      <svg className="h-5 w-5 text-red-500" fill="currentColor" viewBox="0 0 20 20">
                        <path
                          fillRule="evenodd"
                          d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z"
                          clipRule="evenodd"
                        />
                      </svg>
                    ) : null}
                  </div>
                )}
              </div>
              {reason && (
                <p className={`mt-2 text-sm ${isAvailable ? 'text-green-500' : 'text-red-500'}`}>
                  {reason}
                </p>
              )}
            </div>

            <div>
              <label htmlFor="displayName" className="block text-sm font-medium text-gray-300">
                Display Name <span className="text-gray-500">(Optional)</span>
              </label>
              <div className="mt-1">
                <input
                  id="displayName"
                  name="displayName"
                  type="text"
                  maxLength={50}
                  value={displayName}
                  onChange={(e) => setDisplayName(e.target.value)}
                  className="appearance-none block w-full px-3 py-2 border border-[#333] rounded-md shadow-sm placeholder-gray-500 bg-[#222] text-white focus:outline-none focus:ring-[#4a90e2] focus:border-[#4a90e2] sm:text-sm"
                  placeholder="How should we call you?"
                />
              </div>
            </div>

            <div>
              <button
                type="submit"
                disabled={isSubmitting || isAvailable !== true}
                className="w-full flex justify-center py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-[#4a90e2] hover:bg-[#357abd] focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-[#4a90e2] focus:ring-offset-[#1a1a1a] disabled:opacity-50 transition-colors"
              >
                {isSubmitting ? 'Saving...' : 'Continue'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

export default function SetupPage() {
  return (
    <Suspense fallback={<div className="min-h-screen bg-[#111111]" />}>
      <SetupContent />
    </Suspense>
  );
