'use client';

import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { AlertCircle, Ban, Clock, ShieldAlert, X } from 'lucide-react';

interface BanModalProps {
  isOpen: boolean;
  targetUsername: string;
  scope: 'platform' | 'stream';
  onClose: () => void;
  onConfirm: (type: 'ban' | 'timeout', duration: string, reason: string) => void;
}

export function BanModal({ isOpen, targetUsername, scope, onClose, onConfirm }: BanModalProps) {
  const [type, setType] = useState<'ban' | 'timeout'>('timeout');
  const [duration, setDuration] = useState('1hr');
  const [reason, setReason] = useState('');

  // Reset state on open
  useEffect(() => {
    if (isOpen) {
      setType('timeout');
      setDuration('1hr');
      setReason('');
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const handleConfirm = () => {
    onConfirm(type, type === 'ban' ? 'permanent' : duration, reason);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6 bg-[#0a0a0a]/80 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="relative bg-[#111] border border-white/10 text-white rounded-[2.5rem] shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-200">
        <div
          className={`absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r ${type === 'ban' ? 'from-red-600 to-red-400' : 'from-amber-600 to-amber-400'}`}
        />

        {/* Header */}
        <div className="p-8 pb-4 flex justify-between items-start">
          <div className="space-y-1">
            <div className="flex items-center gap-3">
              <ShieldAlert
                className={`w-6 h-6 ${type === 'ban' ? 'text-red-500' : 'text-amber-500'}`}
              />
              <h2 className="text-2xl font-black tracking-tighter">Restrict Access</h2>
            </div>
            <p className="text-gray-500 text-sm font-medium">
              Restricting <span className="text-white font-bold">@{targetUsername}</span> on {scope}
            </p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/5 rounded-full transition-colors">
            <X className="w-5 h-5 text-gray-500" />
          </button>
        </div>

        {/* Content */}
        <div className="px-8 py-4 space-y-8">
          {/* Action Type */}
          <div className="space-y-4">
            <label className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-500">
              Action Type
            </label>
            <div className="grid grid-cols-2 gap-4">
              <button
                onClick={() => setType('timeout')}
                className={`flex items-center justify-center gap-2 py-4 rounded-2xl border transition-all font-bold text-sm ${
                  type === 'timeout'
                    ? 'bg-amber-500/10 border-amber-500/50 text-amber-500'
                    : 'bg-white/[0.03] border-white/5 text-gray-500 hover:bg-white/[0.06]'
                }`}
              >
                <Clock className="w-4 h-4" /> Timeout
              </button>
              <button
                onClick={() => setType('ban')}
                className={`flex items-center justify-center gap-2 py-4 rounded-2xl border transition-all font-bold text-sm ${
                  type === 'ban'
                    ? 'bg-red-500/10 border-red-500/50 text-red-500 shadow-[0_0_20px_rgba(239,68,68,0.1)]'
                    : 'bg-white/[0.03] border-white/5 text-gray-500 hover:bg-white/[0.06]'
                }`}
              >
                <Ban className="w-4 h-4" /> Ban
              </button>
            </div>
          </div>

          {/* Duration */}
          {type === 'timeout' ? (
            <div className="space-y-4">
              <label className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-500">
                Duration
              </label>
              <div className="flex flex-wrap gap-2">
                {[
                  { id: '1min', label: '1 Minute' },
                  { id: '1hr', label: '1 Hour' },
                  { id: '1d', label: '1 Day' },
                  { id: '1w', label: '1 Week' },
                  { id: '1mo', label: '1 Month' },
                ].map((d) => (
                  <button
                    key={d.id}
                    onClick={() => setDuration(d.id)}
                    className={`px-4 py-2 rounded-xl border text-[11px] font-black uppercase tracking-tighter transition-all ${
                      duration === d.id
                        ? 'bg-white/10 border-white/20 text-white'
                        : 'bg-transparent border-white/5 text-gray-600 hover:text-gray-400 hover:border-white/10'
                    }`}
                  >
                    {d.label}
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-500">
                Duration
              </label>
              <div className="px-4 py-2 bg-red-500/10 border border-red-500/20 rounded-xl text-red-500 font-black text-xs uppercase tracking-widest inline-block">
                Permanent
              </div>
            </div>
          )}

          {/* Reason */}
          <div className="space-y-4">
            <label className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-500">
              Reason (Optional)
            </label>
            <input
              placeholder="Reason for restriction..."
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              className="w-full bg-white/[0.03] border border-white/10 rounded-2xl px-4 py-4 text-sm focus:outline-none focus:ring-2 focus:ring-red-500/30 transition-all placeholder:text-gray-700"
            />
          </div>

          {/* Warning Text */}
          <div
            className={`p-5 rounded-[1.5rem] flex items-start gap-4 transition-colors ${
              type === 'ban'
                ? 'bg-red-500/5 border border-red-500/10'
                : 'bg-amber-500/5 border border-amber-500/10'
            }`}
          >
            <AlertCircle
              className={`w-5 h-5 mt-0.5 shrink-0 ${type === 'ban' ? 'text-red-500' : 'text-amber-500'}`}
            />
            <p className="text-[11px] font-medium leading-relaxed text-gray-400">
              <strong className="text-white block mb-0.5">Note:</strong>
              {type === 'ban'
                ? 'This user will be completely blocked from the platform. All active sessions will be terminated immediately.'
                : 'The user will be able to browse but cannot interact (vote, add songs, etc.) for the selected duration.'}
            </p>
          </div>
        </div>

        {/* Footer */}
        <div className="p-8 pt-4 flex gap-3">
          <Button
            variant="ghost"
            onClick={onClose}
            className="flex-1 rounded-2xl text-gray-500 hover:bg-white/5 h-12 font-bold"
          >
            Cancel
          </Button>
          <Button
            onClick={handleConfirm}
            className={`flex-1 rounded-2xl font-bold h-12 transition-all shadow-lg ${
              type === 'ban'
                ? 'bg-red-600 hover:bg-red-500 text-white shadow-red-900/20'
                : 'bg-amber-600 hover:bg-amber-500 text-white shadow-amber-900/20'
            }`}
          >
            Apply {type.charAt(0).toUpperCase() + type.slice(1)}
          </Button>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Music, Play, User, ChevronDown, ChevronUp } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import Link from 'next/link';

interface FriendActivity {
  id: string;
  username: string;
  displayName: string;
  image: string | null;
  email: string;
  isListening: boolean;
  creatorId: string | null;
  partyCode: string | null;
  songTitle: string | null;
  lastSeen: string | null;
}

export function FriendActivityFeed() {
  const [activity, setActivity] = useState<FriendActivity[]>([]);
  const [loading, setLoading] = useState(true);
  const [isExpanded, setIsExpanded] = useState(false);

  const fetchActivity = async () => {
    try {
      const res = await fetch('/api/friends/activity');
      if (res.ok) {
        const data = await res.json();
        setActivity(data.activity);
      }
     } catch (err) {
       // eslint-disable-next-line no-console
       console.error('Failed to fetch friend activity', err);
     } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchActivity();
    const interval = setInterval(fetchActivity, 15000);
    return () => clearInterval(interval);
  }, []);

  if (loading && activity.length === 0) return null;
  if (activity.length === 0)
    return (
      <div className="text-center py-8 px-4 bg-white/[0.02] border border-dashed border-white/5 rounded-2xl">
        <p className="text-xs text-gray-500 italic">
          No activity yet. Add friends to see what they&apos;re listening to!
        </p>
      </div>
    );

  return (
    <div className="space-y-4">
      <button
        className="w-full flex items-center justify-between text-sm font-bold text-gray-400 uppercase tracking-widest md:cursor-default"
        onClick={() => setIsExpanded(!isExpanded)}
      >
        Friend Activity
        <div className="flex items-center gap-2">
          <span className="text-[10px] font-black bg-white/5 px-2 py-0.5 rounded-full">
            {activity.filter((a) => a.isListening).length} ONLINE
          </span>
          <div className="md:hidden">
            {isExpanded ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
          </div>
        </div>
      </button>
      <div className={`${isExpanded ? 'block' : 'hidden'} md:block space-y-3`}>
        {activity.map((friend) => (
          <div key={friend.id}>
            {friend.isListening ? (
              <div className="group flex items-center gap-3 p-3 rounded-2xl bg-white/[0.03] border border-white/5 hover:bg-white/[0.05] transition-all hover:border-blue-500/20 active:scale-[0.98]">
                <div className="relative shrink-0">
                  <div className="w-10 h-10 rounded-2xl bg-gradient-to-br from-green-500/20 to-blue-500/20 border border-green-500/30 flex items-center justify-center font-bold text-green-500 overflow-hidden">
                    {friend.image ? (
                      <img src={friend.image} className="w-full h-full object-cover" />
                    ) : (
                      <User className="w-5 h-5 text-green-500" />
                    )}
                  </div>
                  <div className="absolute -bottom-1 -right-1 w-3.5 h-3.5 bg-green-500 rounded-full border-2 border-gray-900 shadow-[0_0_10px_rgba(34,197,94,0.4)] animate-pulse" />
                </div>
                <div className="flex-1 min-w-0">
                  <Link
                    href={`/user/${friend.username}`}
                    className="text-xs font-black text-white truncate hover:text-primary transition-colors cursor-pointer"
                  >
                    @{friend.username}
                  </Link>
                  <p className="text-[10px] text-blue-400 font-bold flex items-center gap-1.5 truncate mt-0.5">
                    <Music className="w-3 h-3 animate-bounce shadow-blue-500/50" />
                    {friend.songTitle || 'Vibing...'}
                  </p>
                </div>
                <Link
                  href={`/party/${friend.partyCode || friend.creatorId}`}
                  className="p-2.5 rounded-xl bg-blue-600/10 text-blue-400 hover:bg-blue-600 hover:text-white transition-all shadow-inner"
                  title="Join Stream"
                >
                  <Play className="w-3.5 h-3.5 fill-current" />
                </Link>
              </div>
            ) : (
              <div className="flex items-center gap-3 p-3 rounded-2xl opacity-40 grayscale group hover:opacity-100 hover:grayscale-0 transition-all hover:bg-white/[0.02]">
                <div className="w-10 h-10 rounded-2xl bg-gray-800/20 border border-white/5 flex items-center justify-center text-gray-600 shrink-0">
                  {friend.image ? (
                    <img src={friend.image} className="w-full h-full object-cover rounded-2xl" />
                  ) : (
                    <User className="w-5 h-5" />
                  )}
                </div>
                <div className="flex-1 min-w-0">
                  <Link
                    href={`/user/${friend.username}`}
                    className="text-xs font-bold text-gray-400 group-hover:text-white transition-colors truncate hover:text-primary cursor-pointer"
                  >
                    @{friend.username}
                  </Link>
                  <p className="text-[10px] text-gray-600 font-medium truncate mt-0.5">
                    {friend.lastSeen
                      ? `Last seen ${formatDistanceToNow(new Date(friend.lastSeen))} ago`
                      : 'Offline'}
                  </p>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Check, X, User } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { toast } from 'react-toastify';

interface FriendRequest {
  id: string;
  requester: {
    id: string;
    username: string;
    displayName: string;
    image: string | null;
  };
}

export function FriendRequests() {
  const [requests, setRequests] = useState<FriendRequest[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchRequests = async () => {
    try {
      const res = await fetch('/api/friends/requests');
      if (res.ok) {
        const data = await res.json();
        setRequests(data.requests);
      }
    } catch (err) {
      console.error('Failed to fetch requests', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRequests();
  }, []);

  const handleRespond = async (friendshipId: string, action: 'accept' | 'block') => {
    try {
      const res = await fetch('/api/friends/respond', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ friendshipId, action }),
      });

      if (res.ok) {
        toast.success(`Friend request ${action}ed`);
        setRequests((prev) => prev.filter((r) => r.id !== friendshipId));
      } else {
        toast.error('Failed to respond to request');
      }
    } catch (err) {
      toast.error('Error responding to request');
    }
  };

  if (loading) return null;
  if (requests.length === 0) return null;

  return (
    <div className="space-y-4">
      <h3 className="text-sm font-bold flex items-center gap-2 text-gray-400 uppercase tracking-widest">
        Pending Requests ({requests.length})
      </h3>
      <div className="space-y-2">
        {requests.map((req) => (
          <div
            key={req.id}
            className="flex items-center justify-between p-3 bg-white/5 border border-white/5 rounded-2xl animate-in slide-in-from-right-2 duration-300"
          >
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 rounded-full bg-gray-800 flex items-center justify-center overflow-hidden shrink-0 border border-white/10">
                {req.requester.image ? (
                  <img src={req.requester.image} className="w-full h-full object-cover" />
                ) : (
                  <User className="w-4 h-4 text-gray-500" />
                )}
              </div>
              <div className="min-w-0">
                <p className="text-xs font-bold text-white truncate">@{req.requester.username}</p>
                <p className="text-[10px] text-gray-500 truncate">
                  {req.requester.displayName || 'Echoer'}
                </p>
              </div>
            </div>
            <div className="flex gap-1 shrink-0">
              <Button
                size="icon"
                variant="ghost"
                className="h-8 w-8 rounded-lg bg-green-500/10 text-green-500 hover:bg-green-500/20 border border-green-500/20"
                onClick={() => handleRespond(req.id, 'accept')}
              >
                <Check className="w-4 h-4" />
              </Button>
              <Button
                size="icon"
                variant="ghost"
                className="h-8 w-8 rounded-lg bg-red-500/10 text-red-500 hover:bg-red-500/20 border border-red-500/20"
                onClick={() => handleRespond(req.id, 'block')}
              >
                <X className="w-4 h-4" />
              </Button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { signIn } from 'next-auth/react';
import { X, Mail, LogIn, ChevronRight } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';

interface GuestJoinModalProps {
  isOpen: boolean;
  streamTitle: string;
  creatorUsername: string;
  callbackUrl: string;
  onClose: () => void;
}

export function GuestJoinModal({
  isOpen,
  _streamTitle,
  creatorUsername,
  callbackUrl,
  onClose,
}: GuestJoinModalProps) {
  const [email, setEmail] = useState('');
  const [isEmailSent, setIsEmailSent] = useState(false);
  const [loading, setLoading] = useState(false);

  if (!isOpen) return null;

  const handleEmailSignin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) return;
    setLoading(true);
    try {
      await signIn('email', { email, callbackUrl, redirect: false });
      setIsEmailSent(true);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

