    | 'USER_BANNED_PLATFORM'
    | 'USER_BANNED_STREAM'
    | 'USER_TIMED_OUT_PLATFORM'
    | 'USER_TIMED_OUT_STREAM'
    | 'CREATOR_ROLE_REVOKED'
    | 'STREAM_FORCE_CLOSED'
    | 'MOD_PROMOTED'
    | 'MOD_DEMOTED'
