        // Non-blocking: check if creator is already favorited
        fetch('/api/user/favorites')
          .then((r) => (r.ok ? r.json() : null))
          .then((favData) => {
            if (!favData) return;
             const alreadyFav = favData.favorites?.some((f: Record<string, unknown>) => f.id === creatorId);
            setIsFavorite(!!alreadyFav);
