  // }, [currentVideo?.id]);

  // Apply cached sync once player is ready
  useEffect(() => {
    if (lastSync && playerRef.current) {
      console.log('🎯 Applying last cached sync:', lastSync);
      playerRef.current.seekTo(lastSync.currentTime, true);
      if (lastSync.type === 'play') {
        setPlaying(true);
        setIsPaused(false);
