      toast.error('Error saving settings');
    } finally {
      setIsSavingMetadata(false);
    }
  };

  return (
    <div className="flex min-h-screen flex-col bg-gray-950 px-3 sm:px-6 md:px-12 lg:px-20 pt-4 md:pt-6 pb-safe text-white overflow-x-hidden">
